logging.basicConfig(filename='directory_cleanup.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def is_file_in_use(file_path):
    """Check if a file is currently in use by any running process."""
    for proc in psutil.process_iter(['pid', 'name']):
        try:
            if proc.info['pid'] == os.getpid():
                return True
        except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
            pass
    return False

def delete_file(file_path):
    """Delete a file if it's not in use."""
    try:
        os.remove(file_path)
        logging.info(f"Deleted file: {file_path}")
    except OSError as e:
        logging.error(f"Failed to delete file: {file_path}. Error: {e}")

